212	export async function resolveTree(
213	  index: z.infer<typeof registryIndexSchema>,
214	  names: string[]
215	) {
216	  const tree: z.infer<typeof registryIndexSchema> = []
217	
218	  for (const name of names) {
219	    const entry = index.find((entry) => entry.name === name)
220	
221	    if (!entry) {
222	      continue
223	    }
224	
225	    tree.push(entry)
226	
227	    if (entry.registryDependencies) {
228	      const dependencies = await resolveTree(index, entry.registryDependencies)
229	      tree.push(...dependencies)
230	    }
231	  }
232	
233	  return tree.filter(
234	    (component, index, self) =>
235	      self.findIndex((c) => c.name === component.name) === index
236	  )
237	}
