21	function getBaseForStyle(styleName: string) {
22	  for (const base of BASES) {
23	    if (styleName.startsWith(`${base.name}-`)) {
24	      return base.name
25	    }
26	  }
27	  return null
28	}
29	
30	function getDemoIndexKey(styleName: string) {
31	  if (ExamplesIndex[styleName]) {
32	    return styleName
