content.text:
I have completed my thorough exploration of the codebase. Here is the full implementation plan.

---

## Stepper Component Implementation Plan

### 1. Files to Create

Two new files:

- **`apps/v4/registry/new-york-v4/ui/stepper.tsx`** -- the main compound component
- **`apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`** -- the demo example

### 2. Registry Entries to Add

**In `apps/v4/registry/new-york-v4/ui/_registry.ts`**, add this entry into the `ui` array. Since the array is sorted alphabetically and "stepper" falls between "spinner" and "switch", insert it after the `spinner` entry (after line 563):

```ts
{
  name: "stepper",
  type: "registry:ui",
  dependencies: ["lucide-react"],
  files: [
    {
      path: "ui/stepper.tsx",
      type: "registry:ui",
    },
  ],
},
```

No `registryDependencies` needed -- the Stepper is self-contained with no imports of other shadcn components. The only external dependency is `lucide-react` for the `CheckIcon`.

**In `apps/v4/registry/new-york-v4/examples/_registry.ts`**, add an entry into the `examples` array. Place it in alphabetical order among existing entries (near other "s" entries):

```ts
{
  name: "stepper-demo",
  type: "registry:example",
  registryDependencies: ["stepper"],
  files: [
    {
      path: "examples/stepper-demo.tsx",
      type: "registry:example",
    },
  ],
},
```

### 3. Detailed Design of `stepper.tsx`

#### File Header

```tsx
"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"
```

Rationale: Uses `"use client"` because the component manages interactive state. Imports `CheckIcon` from lucide-react for the completed-step indicator (consistent with how `CheckIcon` is used in select.tsx, combobox.tsx, etc.). Imports `cn` from `@/lib/utils` per convention.

#### Types

```tsx
type StepperProps = {
  defaultValue?: number
  value?: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
  linear?: boolean
}

type StepperContextProps = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
  linear: boolean
  totalSteps: number
  registerStep: (step: number) => void
  unregisterStep: (step: number) => void
}

type StepperItemContextProps = {
  step: number
  state: "completed" | "active" | "upcoming"
}
```

Design decisions:
- **`value`/`onValueChange`/`defaultValue`**: This mirrors the SidebarProvider pattern at `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775504564704-dwzo3r/apps/v4/registry/new-york-v4/ui/sidebar.tsx` lines 56-80 for controlled/uncontrolled usage. The value is a numeric step index (1-based).
- **`linear`**: When true, users can only click on the next step or previous steps, not skip ahead. Defaults to `false`.
- **Two contexts**: A `StepperContext` for root-level shared state and a `StepperItemContext` so child components (StepperTrigger, StepperTitle, etc.) can know which step they belong to and its state without prop-drilling.

#### Context Setup

```tsx
const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}
```

This follows exactly the pattern from carousel.tsx (lines 33-43).

#### Stepper (Root Component)

```tsx
function Stepper({
  defaultValue = 1,
  value: valueProp,
  onValueChange,
  orientation = "horizontal",
  linear = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [_activeStep, _setActiveStep] = React.useState(defaultValue)
  const activeStep = valueProp ?? _activeStep
  const [steps, setSteps] = React.useState<number[]>([])

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (onValueChange) {
        onValueChange(step)
      } else {
        _setActiveStep(step)
      }
    },
    [onValueChange]
  )

  const registerStep = React.useCallback((step: number) => {
    setSteps((prev) => {
      if (prev.includes(step)) return prev
      return [...prev, step].sort((a, b) => a - b)
    })
  }, [])

  const unregisterStep = React.useCallback((step: number) => {
    setSteps((prev) => prev.filter((s) => s !== step))
  }, [])

  const contextValue = React.useMemo<StepperContextProps>(
    () => ({
      activeStep,
      setActiveStep,
      orientation,
      linear,
      totalSteps: steps.length,
      registerStep,
      unregisterStep,
    }),
    [activeStep, setActiveStep, orientation, linear, steps.length, registerStep, unregisterStep]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex gap-4",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        role="group"
        aria-label="progress"
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}
```

Key design decisions:
- **Controlled/uncontrolled**: Same pattern as SidebarProvider. If `valueProp` is provided, it takes precedence over internal state. If `onValueChange` is provided, it is called; otherwise internal state is set.
- **`useMemo` for context value**: Prevents unnecessary re-renders, following the sidebar pattern (line 116-127 of sidebar.tsx).
- **`role="group"` and `aria-label="progress"`**: Semantic grouping. Not using `role="navigation"` because a stepper indicates progress, not navigation.
- **`data-orientation`**: Used for Tailwind group-data selectors in children, exactly like tabs.tsx.
- **`group/stepper`**: Named Tailwind group so children can use `group-data-[orientation=horizontal]/stepper:...` selectors.
- **Step registration**: The `registerStep`/`unregisterStep` pattern allows `totalSteps` to be computed dynamically rather than requiring users to declare it explicitly.

#### StepperItem

```tsx
function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep, registerStep, unregisterStep } = useStepper()

  React.useEffect(() => {
    registerStep(step)
    return () => unregisterStep(step)
  }, [step, registerStep, unregisterStep])

  const state: "completed" | "active" | "upcoming" =
    activeStep > step ? "completed" : activeStep === step ? "active" : "upcoming"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "group/stepper-item flex items-center gap-3",
          "group-data-[orientation=vertical]/stepper:flex-row",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}
```

Key decisions:
- **`step` prop is required**: A numeric identifier for ordering. This is explicit rather than implicit (index-based) to give users full control.
- **`data-state`**: Exposes `"completed"`, `"active"`, or `"upcoming"` as a data attribute. This is the primary mechanism for state-dependent styling and follows the pattern used throughout the codebase (e.g., `data-[state=open]` in accordion, `data-[state=active]` in tabs).
- **`group/stepper-item`**: Named group so children (trigger, title, description) can style based on the item's state.

#### StepperTrigger

```tsx
function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { activeStep, setActiveStep, linear } = useStepper()
  const { step, state } = useStepperItem()

  const isDisabled = linear && step > activeStep + 1

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      role="tab"
      aria-current={state === "active" ? "step" : undefined}
      disabled={isDisabled}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        "data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=upcoming]:border-muted-foreground/25 data-[state=upcoming]:bg-background data-[state=upcoming]:text-muted-foreground",
        className
      )}
      onClick={() => setActiveStep(step)}
      {...props}
    >
      {children ?? (state === "completed" ? <CheckIcon className="size-4" /> : step)}
    </button>
  )
}
```

Key decisions:
- **Default content**: If no children are passed, completed steps show a `CheckIcon` and other steps show the step number. Users can override by passing children.
- **`linear` enforcement**: When `linear` is true, steps more than 1 ahead of the current step are disabled. Going backwards is always allowed.
- **`role="tab"` and `aria-current="step"`**: Provides accessibility semantics for step navigation. The active step gets `aria-current="step"`.
- **Focus-visible styling**: Matches the exact same pattern used in tabs.tsx and accordion.tsx for focus ring styling.
- **Circular shape**: `rounded-full` with `size-8` for a standard step indicator circle.

#### StepperTitle

```tsx
function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium leading-none",
        "data-[state=active]:text-foreground",
        "data-[state=completed]:text-foreground",
        "data-[state=upcoming]:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}
```

Follows the CardTitle pattern exactly -- a `div` with `data-slot`, text styling, `cn()` merge. Uses `data-state` for conditional coloring.

#### StepperDescription

```tsx
function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-sm text-muted-foreground",
        "data-[state=upcoming]:text-muted-foreground/60",
        className
      )}
      {...props}
    />
  )
}
```

Mirrors `CardDescription` from card.tsx.

#### StepperSeparator

```tsx
function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-state={state}
      data-orientation={orientation}
      role="separator"
      className={cn(
        "bg-muted-foreground/25 transition-colors data-[state=completed]:bg-primary",
        "data-[orientation=horizontal]:h-0.5 data-[orientation=horizontal]:w-full data-[orientation=horizontal]:flex-1",
        "data-[orientation=vertical]:ml-4 data-[orientation=vertical]:h-full data-[orientation=vertical]:min-h-4 data-[orientation=vertical]:w-0.5",
        className
      )}
      {...props}
    />
  )
}
```

Key decisions:
- **Color transition**: The separator is colored with `bg-primary` when the step it belongs to is completed, providing the visual "fill" effect as users progress.
- **Orientation-aware sizing**: Horizontal = thin horizontal line that fills available space (`h-0.5 w-full flex-1`); vertical = thin vertical line with a minimum height (`w-0.5 min-h-4`).
- **`role="separator"`**: Semantic HTML, matching the pattern in separator.tsx.

#### StepperContent

```tsx
function StepperContent({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  if (state !== "active") return null

  return (
    <div
      data-slot="stepper-content"
      data-state={state}
      role="tabpanel"
      className={cn("mt-2", className)}
      {...props}
    >
      {children}
    </div>
  )
}
```

Key decisions:
- **Conditional rendering**: Only renders when the parent StepperItem's state is `"active"`. This is the simplest approach -- no animation. If animation is desired later, this could use CSS transitions with `data-[state]` instead of conditional mounting.
- **`role="tabpanel"`**: Pairs with `role="tab"` on StepperTrigger for accessibility.

#### Export Block

```tsx
export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
