Rationale: Uses `"use client"` because the component manages interactive state. Imports `CheckIcon` from lucide-react for the completed-step indicator (consistent with how `CheckIcon` is used in select.tsx, combobox.tsx, etc.). Imports `cn` from `@/lib/utils` per convention.

#### Types

```tsx
type StepperProps = {
  defaultValue?: number
  value?: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
  linear?: boolean
}

type StepperContextProps = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
  linear: boolean
  totalSteps: number
  registerStep: (step: number) => void
  unregisterStep: (step: number) => void
}

type StepperItemContextProps = {
  step: number
  state: "completed" | "active" | "upcoming"
}
