      data-state={state}
      type="button"
      role="tab"
      aria-current={state === "active" ? "step" : undefined}
      disabled={isDisabled}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        "data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=upcoming]:border-muted-foreground/25 data-[state=upcoming]:bg-background data-[state=upcoming]:text-muted-foreground",
