"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    title: "Account",
    description: "Create your account",
  },
  {
    title: "Profile",
    description: "Set up your profile",
  },
  {
    title: "Complete",
    description: "Review and confirm",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  return (
    <div className="flex w-full max-w-lg flex-col gap-6">
      <Stepper activeStep={activeStep} onStepChange={setActiveStep}>
        {steps.map((step, index) => (
          <React.Fragment key={step.title}>
            <StepperItem step={index}>
              <StepperTrigger>
                <StepperIndicator />
                <div className="flex flex-col">
                  <StepperTitle>{step.title}</StepperTitle>
                  <StepperDescription>{step.description}</StepperDescription>
                </div>
              </StepperTrigger>
            </StepperItem>
            {index < steps.length - 1 && (
              <StepperItem step={index}>
                <StepperSeparator />
              </StepperItem>
            )}
          </React.Fragment>
        ))}
      </Stepper>
      <div className="rounded-lg border bg-card p-6 text-card-foreground shadow-sm">
        {activeStep === 0 && (
          <p className="text-sm text-muted-foreground">
            Enter your email address and choose a secure password to create your
            account.
          </p>
        )}
        {activeStep === 1 && (
          <p className="text-sm text-muted-foreground">
            Add your name, avatar, and bio to personalize your profile.
          </p>
        )}
        {activeStep === 2 && (
          <p className="text-sm text-muted-foreground">
            Review your account details and confirm everything looks correct.
          </p>
        )}
      </div>
      <div className="flex justify-between">
        <Button
          variant="outline"
          onClick={() => setActiveStep(Math.max(0, activeStep - 1))}
          disabled={activeStep === 0}
        >
          Previous
        </Button>
        <Button
          onClick={() =>
            setActiveStep(Math.min(steps.length - 1, activeStep + 1))
          }
          disabled={activeStep === steps.length - 1}
        >
          Next
        </Button>
      </div>
    </div>
  )
}

