"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
  onStepChange?: (step: number) => void
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepItemContextProps = {
  step: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepItemContext = React.createContext<StepItemContextProps | null>(null)

function useStepItem() {
  const context = React.useContext(StepItemContext)

  if (!context) {
    throw new Error("useStepItem must be used within a <StepperItem />")
  }

  return context
}

function Stepper({
  activeStep = 0,
  orientation = "horizontal",
  onStepChange,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep?: number
  orientation?: "horizontal" | "vertical"
  onStepChange?: (step: number) => void
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation, onStepChange }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          orientation === "horizontal"
            ? "flex-row items-center gap-2"
            : "flex-col gap-2",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}) {
  const { activeStep } = useStepper()
  const isActive = activeStep === step
  const isCompleted = activeStep > step
  const isDisabled = disabled

  return (
    <StepItemContext.Provider
      value={{ step, isActive, isCompleted, isDisabled }}
    >
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
        className={cn(
          "group/stepper-item flex items-center gap-2",
          "data-[state=completed]:text-primary data-[state=active]:text-primary",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange } = useStepper()
  const { step, isActive, isCompleted, isDisabled } = useStepItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      disabled={isDisabled}
      className={cn(
        "inline-flex items-center gap-3 rounded-md text-sm font-medium transition-colors focus-visible:outline-1 focus-visible:outline-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        "cursor-pointer",
        className
      )}
      onClick={() => onStepChange?.(step)}
      {...props}
    >
      {children}
    </button>
  )
}

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { isActive, isCompleted, step } = useStepItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
        isCompleted &&
          "border-primary bg-primary text-primary-foreground",
        isActive &&
          "border-primary bg-primary text-primary-foreground",
        !isActive &&
          !isCompleted &&
          "border-muted-foreground/40 text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? (isCompleted ? "✓" : step + 1)}
    </span>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"h4">) {
  const { isActive, isCompleted } = useStepItem()

  return (
    <h4
      data-slot="stepper-title"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      className={cn(
        "text-sm font-semibold transition-colors",
        (isActive || isCompleted) ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { isActive, isCompleted } = useStepItem()

  return (
    <p
      data-slot="stepper-description"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      className={cn(
        "text-xs text-muted-foreground transition-colors",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { isCompleted } = useStepItem()

  return (
    <div
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "inactive"}
      className={cn(
        "transition-colors",
        orientation === "horizontal"
          ? "h-0.5 flex-1 rounded-full"
          : "ml-4 w-0.5 min-h-4 flex-1 rounded-full",
        isCompleted ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  const { activeStep } = useStepper()
  const { step } = useStepItem()

  if (activeStep !== step) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-4 text-sm text-foreground", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}
